import os
import json
import re

# ── 설정 ──────────────────────────────────────────
R2_PUBLIC_URL = "https://ancient-silence-7a1d.js-pdf.workers.dev"
PDF_DIR       = r"C:\Users\USER\Desktop\APMATH\AP\ready_for_r2"
OUTPUT_FILE   = r"C:\Users\USER\Desktop\APMATH\AP\data\catalog.json"
# ──────────────────────────────────────────────────

EXAM_MAP = {
    "1중간": "1중간",
    "1기말": "1기말",
    "2중간": "2중간",
    "2기말": "2기말",
    "1학기중간": "1중간",
    "1학기기말": "1기말",
    "2학기중간": "2중간",
    "2학기기말": "2기말",
}

SUBJECT_CANDIDATES = [
    "경제수학", "확률과통계", "확통", "미적분1", "미적분2", "기하와벡터",
    "기하", "수학", "수1", "수2", "공통수학1", "공통수학2", "대수"
]

def normalize_exam(text: str | None) -> str | None:
    if not text:
        return None
    text = text.strip()
    return EXAM_MAP.get(text, text)

def extract_grade(school: str | None) -> str | None:
    if not school:
        return None
    m = re.search(r"(중|고)([123])", school)
    if m:
        return f"{m.group(1)}{m.group(2)}"
    return None

def classify_type(stem: str) -> str:
    if "해설" in stem or "풀이" in stem:
        return "sol"
    if "정답" in stem:
        return "ans"
    if "문제지" in stem or "문제" in stem:
        return "q"
    return "q"

def parse_filename(filename: str):
    stem = os.path.splitext(filename)[0]
    parts = stem.split("_")

    if len(parts) < 4:
        return None

    year = parts[0].strip()
    if not re.fullmatch(r"\d{4}", year):
        return None

    school = parts[1].strip()
    grade = extract_grade(school)

    exam_idx = -1
    exam = None
    for i, p in enumerate(parts):
        p_norm = normalize_exam(p)
        if p_norm in {"1중간", "1기말", "2중간", "2기말"}:
            exam_idx = i
            exam = p_norm
            break

    if exam_idx == -1 or exam is None:
        return None

    kind = classify_type(stem)

    middle_parts = [p.strip() for p in parts[2:exam_idx] if p.strip()]

    subject = None
    for candidate in SUBJECT_CANDIDATES:
        if candidate in middle_parts:
            subject = candidate
            break

    if subject is None:
        joined = "_".join(middle_parts)
        for candidate in SUBJECT_CANDIDATES:
            if candidate in joined:
                subject = candidate
                break

    if subject is None:
        subject = "수학"

    return {
        "year": year,
        "school": school,
        "grade": grade,
        "subject": subject,
        "exam": exam,
        "kind": kind,
        "filename": filename,
    }

def collect_pdfs(root: str):
    result = []
    for f in os.listdir(root):
        full = os.path.join(root, f)
        if os.path.isfile(full) and f.lower().endswith(".pdf"):
            result.append(f)
    return sorted(result)

def build_public_url(filename: str) -> str:
    return f"{R2_PUBLIC_URL}/{filename}"

def extract_metadata():
    if not os.path.exists(PDF_DIR):
        print(f"❌ 폴더 없음: {PDF_DIR}")
        return

    all_pdfs = collect_pdfs(PDF_DIR)
    print(f"🔍 PDF 총 {len(all_pdfs)}개 발견")

    entries = {}
    skipped = []

    for filename in all_pdfs:
        meta = parse_filename(filename)
        if not meta:
            skipped.append(filename)
            continue

        key = (
            meta["year"],
            meta["school"],
            meta["grade"],
            meta["subject"],
            meta["exam"],
        )

        url = build_public_url(filename)

        if key not in entries:
            entries[key] = {
                "year": meta["year"],
                "school": meta["school"],
                "grade": meta["grade"],
                "subject": meta["subject"],
                "exam": meta["exam"],
                "fileName": filename,
            }

        kind = meta["kind"]
        if kind == "q":
            entries[key]["url"] = url
            entries[key]["fileName"] = filename
        elif kind == "sol":
            entries[key]["solUrl"] = url
        elif kind == "ans":
            entries[key]["ansUrl"] = url

    files = [v for v in entries.values() if "url" in v]

    files.sort(
        key=lambda x: (
            -int(x["year"]) if str(x.get("year", "")).isdigit() else 0,
            x.get("school") or "",
            x.get("subject") or "",
            x.get("exam") or "",
        )
    )

    catalog = {"files": files}

    os.makedirs(os.path.dirname(OUTPUT_FILE), exist_ok=True)
    with open(OUTPUT_FILE, "w", encoding="utf-8") as f:
        json.dump(catalog, f, ensure_ascii=False, indent=2)

    sol_count = sum(1 for e in files if "solUrl" in e)
    ans_count = sum(1 for e in files if "ansUrl" in e)

    print(f"\n✅ 완료: {len(files)}개 등록")
    print(f"   해설 연결: {sol_count}개 / 정답 연결: {ans_count}개")
    print(f"   건너뜀: {len(skipped)}개")

    if skipped:
        print("\n[건너뜀 목록]")
        for s in skipped[:30]:
            print(f"  - {s}")
        if len(skipped) > 30:
            print(f"  ... 외 {len(skipped) - 30}개")

if __name__ == "__main__":
    extract_metadata()
